import{_ as e,o as a,c as n,ae as t}from"./chunks/framework.6gkcVjOI.js";const u=JSON.parse('{"title":"Agent Loop Architecture","description":"Understanding the agent loop as a state machine — stop_reason dispatch, safety mechanisms, and design trade-offs","frontmatter":{"title":"Agent Loop Architecture","description":"Understanding the agent loop as a state machine — stop_reason dispatch, safety mechanisms, and design trade-offs"},"headers":[],"relativePath":"core-code/agent-loop-impl.md","filePath":"core-code/agent-loop-impl.md","lastUpdated":1775210533000}'),i={name:"core-code/agent-loop-impl.md"};function r(l,s,o,p,c,h){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="agent-loop-architecture" tabindex="-1">Agent Loop Architecture <a class="header-anchor" href="#agent-loop-architecture" aria-label="Permalink to &quot;Agent Loop Architecture&quot;">​</a></h1><p>The agent loop is the <strong>runtime engine</strong> of the system. While the entry point establishes the dependency graph at startup, the agent loop executes the actual conversation cycles. Viewing it as a <strong>state machine</strong> rather than a procedural loop reveals the core design decisions that make the system robust and predictable.</p><h2 id="state-machine-overview" tabindex="-1">State Machine Overview <a class="header-anchor" href="#state-machine-overview" aria-label="Permalink to &quot;State Machine Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                     Agent Loop State Machine                        │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│     ┌──────────┐                                                   │</span></span>
<span class="line"><span>│     │ thinking │                                                   │</span></span>
<span class="line"><span>│     └────┬─────┘                                                   │</span></span>
<span class="line"><span>│          │ API response received                                    │</span></span>
<span class="line"><span>│          ▼                                                          │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────┐                        │</span></span>
<span class="line"><span>│  │         stop_reason dispatch          │                        │</span></span>
<span class="line"><span>│  └───────────────────────────────────────┘                        │</span></span>
<span class="line"><span>│          │                                                         │</span></span>
<span class="line"><span>│    ┌─────┴─────┬───────────┬────────────┐                       │</span></span>
<span class="line"><span>│    ▼           ▼           ▼            ▼                        │</span></span>
<span class="line"><span>│ ┌──────┐  ┌────────┐  ┌──────────┐  ┌──────────┐                 │</span></span>
<span class="line"><span>│ │end_  │  │max_    │  │tool_use  │  │unknown   │                 │</span></span>
<span class="line"><span>│ │turn  │  │tokens  │  │          │  │          │                 │</span></span>
<span class="line"><span>│ └──┬───┘  └────┬───┘  └────┬─────┘  └────┬─────┘                 │</span></span>
<span class="line"><span>│    │           │           │             │                        │</span></span>
<span class="line"><span>│    ▼           ▼           ▼             ▼                        │</span></span>
<span class="line"><span>│  Return      Return      Execute      Return                      │</span></span>
<span class="line"><span>│  response   +warning   tools +                               │</span></span>
<span class="line"><span>│                           continue                                │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><h2 id="state-definitions" tabindex="-1">State Definitions <a class="header-anchor" href="#state-definitions" aria-label="Permalink to &quot;State Definitions&quot;">​</a></h2><p>The agent loop operates in these states:</p><table tabindex="0"><thead><tr><th>State</th><th>Meaning</th><th>Next Action</th></tr></thead><tbody><tr><td><strong>thinking</strong></td><td>Awaiting API response</td><td>Transition based on <code>stop_reason</code></td></tr><tr><td><strong>tool_use</strong></td><td>Model requested tool execution</td><td>Execute tools, add results, continue loop</td></tr><tr><td><strong>end_turn</strong></td><td>Model completed task</td><td>Return response to user</td></tr><tr><td><strong>max_tokens</strong></td><td>Response truncated</td><td>Return partial response with warning</td></tr><tr><td><strong>unknown</strong></td><td>Unexpected stop reason</td><td>Return whatever content exists</td></tr></tbody></table><h2 id="why-a-state-machine" tabindex="-1">Why a State Machine? <a class="header-anchor" href="#why-a-state-machine" aria-label="Permalink to &quot;Why a State Machine?&quot;">​</a></h2><h3 id="procedural-vs-state-machine-thinking" tabindex="-1">Procedural vs. State Machine Thinking <a class="header-anchor" href="#procedural-vs-state-machine-thinking" aria-label="Permalink to &quot;Procedural vs. State Machine Thinking&quot;">​</a></h3><p>A <strong>procedural</strong> view treats the loop as:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Send request</span></span>
<span class="line"><span>2. Get response</span></span>
<span class="line"><span>3. Check stop_reason</span></span>
<span class="line"><span>4. If tool_use: execute and loop</span></span>
<span class="line"><span>5. Else: return</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>This misses the deeper structure. A <strong>state machine</strong> view reveals:</p><ul><li>Each <code>stop_reason</code> is a <strong>state transition</strong> — the system moves from &quot;thinking&quot; to a specific outcome state</li><li>The loop isn&#39;t just repeating; it&#39;s <strong>cycling through well-defined states</strong></li><li>Safety limits (MAX_TURNS) are <strong>circuit breakers</strong> that halt the state machine</li></ul><h3 id="design-trade-offs" tabindex="-1">Design Trade-offs <a class="header-anchor" href="#design-trade-offs" aria-label="Permalink to &quot;Design Trade-offs&quot;">​</a></h3><p>Why use a state machine instead of alternatives?</p><table tabindex="0"><thead><tr><th>Approach</th><th>Why Not Used</th></tr></thead><tbody><tr><td><strong>Event-driven</strong></td><td>Over-engineered for this use case; the API already provides discrete responses</td></tr><tr><td><strong>Reactive/stream-based</strong></td><td>SSE provides streaming, but we need to reason about complete responses, not individual tokens</td></tr><tr><td><strong>Coroutine-based</strong></td><td>Go&#39;s goroutines are available, but the loop logic is simpler as explicit state transitions</td></tr></tbody></table><p>The state machine is the <strong>minimal complexity</strong> solution that captures the needed behavior: the API tells us what happened (<code>stop_reason</code>), and we respond accordingly.</p><h2 id="stop-reason-dispatch" tabindex="-1">Stop Reason Dispatch <a class="header-anchor" href="#stop-reason-dispatch" aria-label="Permalink to &quot;Stop Reason Dispatch&quot;">​</a></h2><p>The <code>stop_reason</code> field is the <strong>protocol contract</strong> between the API and the agent. It tells the agent what the model did and what to do next:</p><h3 id="end-turn-stop-sequence" tabindex="-1">end_turn / stop_sequence <a class="header-anchor" href="#end-turn-stop-sequence" aria-label="Permalink to &quot;end_turn / stop_sequence&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Model believes task is complete → Return response to user</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This is the <strong>happy path</strong>. The model decided it has enough information and produced a final answer. The agent returns the text content directly.</p><h3 id="max-tokens" tabindex="-1">max_tokens <a class="header-anchor" href="#max-tokens" aria-label="Permalink to &quot;max_tokens&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Model hit token limit → Return partial response with warning</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This is a <strong>degraded but safe</strong> path. The response is truncated, so the user gets partial results plus a warning. They can continue the conversation to get the rest.</p><h3 id="tool-use" tabindex="-1">tool_use <a class="header-anchor" href="#tool-use" aria-label="Permalink to &quot;tool_use&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Model wants to call tools → Execute tools, add results, continue loop</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This is the <strong>iterative path</strong>. The model identified that it needs to take action (read a file, run a command, search for something). The agent:</p><ol><li>Executes all requested tools</li><li>Adds results to conversation history</li><li>Continues the loop to get the next response</li></ol><h3 id="unknown-default" tabindex="-1">unknown / default <a class="header-anchor" href="#unknown-default" aria-label="Permalink to &quot;unknown / default&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Unexpected stop_reason → Return whatever content exists</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This is a <strong>defensive fallback</strong>. We don&#39;t crash on unexpected values; we return what we have and let the user decide what to do.</p><h2 id="circuit-breaker-—-max-turns" tabindex="-1">Circuit Breaker — MAX_TURNS <a class="header-anchor" href="#circuit-breaker-—-max-turns" aria-label="Permalink to &quot;Circuit Breaker — MAX_TURNS&quot;">​</a></h2><div class="language-go vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> MaxTurns</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 50</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>MAX_TURNS is a <strong>circuit breaker</strong> in the electrical safety sense — it&#39;s designed to prevent catastrophic failure:</p><h3 id="what-it-prevents" tabindex="-1">What it prevents <a class="header-anchor" href="#what-it-prevents" aria-label="Permalink to &quot;What it prevents&quot;">​</a></h3><ul><li><strong>Infinite loops</strong>: Model calling tools that produce results that trigger more tool calls endlessly</li><li><strong>Oscillation</strong>: Model going back and forth between same approaches without progress</li><li><strong>Resource exhaustion</strong>: Running out of API tokens, memory, or time</li></ul><h3 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h3><p>The loop enforces a maximum of 50 iterations (each iteration = one API call + potentially many tool executions). After 50 turns, the agent stops and returns a message indicating the limit was reached.</p><h3 id="why-50" tabindex="-1">Why 50? <a class="header-anchor" href="#why-50" aria-label="Permalink to &quot;Why 50?&quot;">​</a></h3><p>This is an <strong>empirical choice</strong>:</p><ul><li>50 turns is enough for complex tasks (analyze codebase, make changes, verify)</li><li>It&#39;s beyond what a reasonable conversation would need</li><li>It provides a safety net without being too restrictive</li></ul><h3 id="what-this-design-choice-means" tabindex="-1">What this design choice means <a class="header-anchor" href="#what-this-design-choice-means" aria-label="Permalink to &quot;What this design choice means&quot;">​</a></h3><p>The circuit breaker assumes that <strong>reasonable tasks complete within 50 turns</strong>. If a task legitimately needs more, the design says: break the task into smaller pieces, or accept that the current approach isn&#39;t working.</p><h2 id="context-window-optimization-—-history-management" tabindex="-1">Context Window Optimization — History Management <a class="header-anchor" href="#context-window-optimization-—-history-management" aria-label="Permalink to &quot;Context Window Optimization — History Management&quot;">​</a></h2><p>The conversation history grows with each turn. The API has a <strong>context window limit</strong> (e.g., 200K tokens). The history management system optimizes this:</p><h3 id="compaction-strategy" tabindex="-1">Compaction Strategy <a class="header-anchor" href="#compaction-strategy" aria-label="Permalink to &quot;Compaction Strategy&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              History Compaction                     │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  Turn 1:  [user: &quot;...&quot;]                             │</span></span>
<span class="line"><span>│           [assistant: &quot;...&quot;]                        │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  Turn 2:  [user: &quot;...&quot;]                             │</span></span>
<span class="line"><span>│           [assistant: &quot;tool_use: read file&quot;]        │</span></span>
<span class="line"><span>│           [tool_result: &quot;file contents...&quot;]        │</span></span>
<span class="line"><span>│           [assistant: &quot;...&quot;]                        │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  ...                                                │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  After compaction:                                  │</span></span>
<span class="line"><span>│  ─────────────────                                  │</span></span>
<span class="line"><span>│  [user: &quot;original request&quot;]                        │</span></span>
<span class="line"><span>│  [system: &quot;summary of middle turns&quot;]               │</span></span>
<span class="line"><span>│  [assistant: &quot;current response&quot;]                   │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><h3 id="why-not-keep-everything" tabindex="-1">Why not keep everything? <a class="header-anchor" href="#why-not-keep-everything" aria-label="Permalink to &quot;Why not keep everything?&quot;">​</a></h3><ul><li><strong>Cost</strong>: More tokens = more API costs</li><li><strong>Performance</strong>: Larger contexts = slower API responses</li><li><strong>Model attention</strong>: Extremely long contexts can reduce model focus on the current task</li></ul><h3 id="compaction-triggers" tabindex="-1">Compaction triggers <a class="header-anchor" href="#compaction-triggers" aria-label="Permalink to &quot;Compaction triggers&quot;">​</a></h3><p>Compaction happens when:</p><ol><li>Token count approaches the limit</li><li>Before each API request (to ensure the request fits)</li></ol><h3 id="what-gets-compacted" tabindex="-1">What gets compacted <a class="header-anchor" href="#what-gets-compacted" aria-label="Permalink to &quot;What gets compacted&quot;">​</a></h3><p>The system summarizes or removes older turns while preserving:</p><ul><li>The original user request (context)</li><li>The most recent conversation (working memory)</li><li>Tool definitions (always needed)</li></ul><h2 id="security-checkpoint-—-permission-gate" tabindex="-1">Security Checkpoint — Permission Gate <a class="header-anchor" href="#security-checkpoint-—-permission-gate" aria-label="Permalink to &quot;Security Checkpoint — Permission Gate&quot;">​</a></h2><p>Before any tool executes, it passes through the <strong>permission gate</strong>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              Permission Gate                         │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  tool_request ──▶ checkPermission() ──▶ decision    │</span></span>
<span class="line"><span>│                      │                              │</span></span>
<span class="line"><span>│                      ▼                              │</span></span>
<span class="line"><span>│              ┌──────────────────┐                   │</span></span>
<span class="line"><span>│              │ PermissionPolicy │                   │</span></span>
<span class="line"><span>│              │  - Allow         │                   │</span></span>
<span class="line"><span>│              │  - Deny          │                   │</span></span>
<span class="line"><span>│              │  - Ask (prompt)  │                   │</span></span>
<span class="line"><span>│              └──────────────────┘                   │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h3 id="why-this-design" tabindex="-1">Why this design? <a class="header-anchor" href="#why-this-design" aria-label="Permalink to &quot;Why this design?&quot;">​</a></h3><ul><li><strong>Defense in depth</strong>: Not all tools are dangerous; permission check is a security layer</li><li><strong>User control</strong>: Users can allow/deny specific operations</li><li><strong>Auditability</strong>: Permission decisions are logged</li></ul><h3 id="tool-classification" tabindex="-1">Tool classification <a class="header-anchor" href="#tool-classification" aria-label="Permalink to &quot;Tool classification&quot;">​</a></h3><ul><li><strong>No permission needed</strong>: Read, Glob, Grep (read-only, low-risk)</li><li><strong>Requires permission</strong>: Bash, Write, Edit (can modify system)</li></ul><p>The permission policy evaluates each tool call based on:</p><ol><li>Whether the tool requires permission</li><li>The user&#39;s configured permission level</li><li>The specific operation being attempted</li></ol><h2 id="crash-recovery-—-session-persistence" tabindex="-1">Crash Recovery — Session Persistence <a class="header-anchor" href="#crash-recovery-—-session-persistence" aria-label="Permalink to &quot;Crash Recovery — Session Persistence&quot;">​</a></h2><p>Each turn completes with session persistence:</p><div class="language-go vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Agent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">saveSession</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">turnCount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">inputTokens</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">outputTokens</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Save to ~/.go-code/sessions/</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="what-gets-saved" tabindex="-1">What gets saved <a class="header-anchor" href="#what-gets-saved" aria-label="Permalink to &quot;What gets saved&quot;">​</a></h3><ul><li>Session ID and timestamps</li><li>Model used</li><li>Turn count and token usage</li><li><strong>Full conversation history</strong></li></ul><h3 id="why-save-after-each-turn" tabindex="-1">Why save after each turn? <a class="header-anchor" href="#why-save-after-each-turn" aria-label="Permalink to &quot;Why save after each turn?&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│            Session Persistence Flow                  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  Turn 1:  request → response → save                 │</span></span>
<span class="line"><span>│  Turn 2:  request → response → save                 │</span></span>
<span class="line"><span>│  Turn 3:  crash!                                    │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  Recovery: Load last session → resume from turn 3  │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>This design provides <strong>crash recovery</strong> without complexity:</p><ul><li>If the process dies mid-turn, the next run can resume</li><li>No complex transaction log needed</li><li>Sessions are small enough to save quickly</li></ul><h3 id="recovery-considerations" tabindex="-1">Recovery considerations <a class="header-anchor" href="#recovery-considerations" aria-label="Permalink to &quot;Recovery considerations&quot;">​</a></h3><ul><li>Sessions saved to disk survive process crash</li><li>On next run, user can continue or start fresh</li><li>Old sessions accumulate (cleanup is a future enhancement)</li></ul><h2 id="architectural-summary" tabindex="-1">Architectural Summary <a class="header-anchor" href="#architectural-summary" aria-label="Permalink to &quot;Architectural Summary&quot;">​</a></h2><p>The agent loop demonstrates several architectural principles:</p><table tabindex="0"><thead><tr><th>Principle</th><th>Implementation</th></tr></thead><tbody><tr><td><strong>State Machine</strong></td><td><code>stop_reason</code> as state transition trigger</td></tr><tr><td><strong>Circuit Breaker</strong></td><td>MAX_TURNS prevents infinite loops</td></tr><tr><td><strong>Context Optimization</strong></td><td>History compaction before each request</td></tr><tr><td><strong>Defense in Depth</strong></td><td>Permission gate before tool execution</td></tr><tr><td><strong>Crash Recovery</strong></td><td>Session persistence after each turn</td></tr><tr><td><strong>Fail Gracefully</strong></td><td>Unknown stop_reason returns partial response</td></tr></tbody></table><h3 id="why-these-choices-work" tabindex="-1">Why these choices work <a class="header-anchor" href="#why-these-choices-work" aria-label="Permalink to &quot;Why these choices work&quot;">​</a></h3><ol><li><strong>State machine</strong>: Matches the API&#39;s discrete response model</li><li><strong>Circuit breaker</strong>: Provides safety without complexity</li><li><strong>History compaction</strong>: Keeps costs predictable, performance high</li><li><strong>Permission gate</strong>: Balances security with usability</li><li><strong>Session persistence</strong>: Enables recovery without transaction complexity</li></ol><p>The agent loop is the <strong>operational core</strong> — it takes the initialized components from the entry point and makes them do useful work through well-defined state transitions.</p><hr><div class="nav-prev-next"><ul><li><a href="./entry-point.html">Entry Point Architecture</a> ←</li><li>→ <a href="./../tools/overview.html">Tool System Overview</a></li></ul></div>`,84)])])}const m=e(i,[["render",r]]);export{u as __pageData,m as default};
